#include <iostream>

using namespace std;

struct Node {
    int val;
    Node *next, *prev;
    Node(int v) : val(v), next(nullptr), prev(nullptr) {}
};

class MyLinkedList {
public:
    Node *head, *tail;
    int size;

    MyLinkedList() : head(nullptr), tail(nullptr), size(0) {}

    Node* getNode(int index)
    {
        Node* cur = head;
        for (int i = 0; i < index; i++) cur = cur->next;
        return cur;
    }

    int get(int index)
    {
        if (index < 0 || index >= size) return -1;
        return getNode(index)->val;
    }

    void addAtHead(int val)
    {
        Node* node = new Node(val);
        node->next = head;
        if (head) head->prev = node;
        head = node;
        if (!tail) tail = node;
        size++;
    }

    void addAtTail(int val)
    {
        Node* node = new Node(val);
        node->prev = tail;
        if (tail) tail->next = node;
        tail = node;
        if (!head) head = node;
        size++;
    }

    void addAtIndex(int index, int val)
    {
        if (index <= 0) { addAtHead(val); return; }
        if (index == size) { addAtTail(val); return; }
        if (index > size) return;

        Node* next = getNode(index);
        Node* prev = next->prev;
        Node* node = new Node(val);

        node->prev = prev; node->next = next;
        prev->next = node; next->prev = node;
        size++;
    }

    void deleteAtIndex(int index)
    {
        if (index < 0 || index >= size) return;

        Node* target = getNode(index);
        if (target->prev) target->prev->next = target->next; else head = target->next;
        if (target->next) target->next->prev = target->prev; else tail = target->prev;

        delete target;
        size--;
    }
};

int main()
{
    MyLinkedList list;
    list.addAtHead(1);
    list.addAtTail(3);
    list.addAtIndex(1, 2);
    cout << list.get(1) << ", ";
    list.deleteAtIndex(1);
    cout << list.get(1) << endl;

    return 0;
}

#include <iostream>
#include <vector>

using namespace std;

class LRUCache {
public:
    int capacity;
    vector<pair<int,int>> items; // most recent at the back

    LRUCache(int cap) : capacity(cap) {}

    int get(int key)
    {
        for (int i = 0; i < items.size(); i++)
        {
            if (items[i].first == key)
            {
                pair<int,int> entry = items[i];
                items.erase(items.begin() + i);
                items.push_back(entry);
                return entry.second;
            }
        }
        return -1;
    }

    void put(int key, int value)
    {
        for (int i = 0; i < items.size(); i++)
        {
            if (items[i].first == key) { items.erase(items.begin() + i); break; }
        }

        if (items.size() == capacity) items.erase(items.begin());

        items.push_back({key, value});
    }
};

int main()
{
    LRUCache cache(2);
    cache.put(1, 1);
    cache.put(2, 2);
    cout << cache.get(1) << ", ";
    cache.put(3, 3);
    cout << cache.get(2) << ", ";
    cache.put(4, 4);
    cout << cache.get(1) << ", " << cache.get(3) << ", " << cache.get(4) << endl;

    return 0;
}

#include <iostream>
#include <unordered_map>

using namespace std;

struct Node {
    int key, value;
    Node *prev, *next;
    Node(int k, int v) : key(k), value(v), prev(nullptr), next(nullptr) {}
};

class LRUCache {
public:
    int capacity;
    unordered_map<int, Node*> cache;
    Node *head, *tail; // head = most recent, tail = least recent

    LRUCache(int cap) : capacity(cap)
    {
        head = new Node(0, 0);
        tail = new Node(0, 0);
        head->next = tail;
        tail->prev = head;
    }

    void remove(Node* node)
    {
        node->prev->next = node->next;
        node->next->prev = node->prev;
    }

    void insertAtFront(Node* node)
    {
        node->next = head->next;
        node->prev = head;
        head->next->prev = node;
        head->next = node;
    }

    int get(int key)
    {
        if (!cache.count(key)) return -1;

        Node* node = cache[key];
        remove(node);
        insertAtFront(node);
        return node->value;
    }

    void put(int key, int value)
    {
        if (cache.count(key))
        {
            remove(cache[key]);
            delete cache[key];
        }

        Node* node = new Node(key, value);
        cache[key] = node;
        insertAtFront(node);

        if (cache.size() > capacity)
        {
            Node* lru = tail->prev;
            remove(lru);
            cache.erase(lru->key);
            delete lru;
        }
    }
};

int main()
{
    LRUCache cache(2);
    cache.put(1, 1);
    cache.put(2, 2);
    cout << cache.get(1) << ", ";
    cache.put(3, 3);
    cout << cache.get(2) << ", ";
    cache.put(4, 4);
    cout << cache.get(1) << ", " << cache.get(3) << ", " << cache.get(4) << endl;

    return 0;
}

#include <iostream>

using namespace std;

struct Node {
    int val;
    Node *prev, *next, *child;
    Node(int v) : val(v), prev(nullptr), next(nullptr), child(nullptr) {}
};

void flattenDFS(Node* node)
{
    while (node != nullptr)
    {
        if (node->child != nullptr)
        {
            Node* next = node->next;
            Node* child = node->child;

            node->next = child;
            child->prev = node;
            node->child = nullptr;

            Node* tail = child;
            while (tail->next != nullptr) tail = tail->next; // find child list's end

            tail->next = next;
            if (next != nullptr) next->prev = tail;

            flattenDFS(child); // recurse into the spliced-in child
        }
        node = node->next;
    }
}

Node* flatten(Node* head)
{
    flattenDFS(head);
    return head;
}

int main()
{
    Node* n1 = new Node(1); Node* n2 = new Node(2); Node* n3 = new Node(3);
    Node* n4 = new Node(4); Node* n5 = new Node(5); Node* n6 = new Node(6);
    Node* c7 = new Node(7); Node* c8 = new Node(8); Node* c9 = new Node(9); Node* c10 = new Node(10);

    n1->next=n2; n2->prev=n1; n2->next=n3; n3->prev=n2; n3->next=n4; n4->prev=n3;
    n4->next=n5; n5->prev=n4; n5->next=n6; n6->prev=n5;
    c7->next=c8; c8->prev=c7; c8->next=c9; c9->prev=c8; c9->next=c10; c10->prev=c9;
    n3->child = c7;

    Node* result = flatten(n1);
    for (Node* n = result; n; n = n->next) cout << n->val << " ";

    return 0;
}

#include <iostream>
#include <stack>

using namespace std;

struct Node {
    int val;
    Node *prev, *next, *child;
    Node(int v) : val(v), prev(nullptr), next(nullptr), child(nullptr) {}
};

Node* flatten(Node* head)
{
    if (head == nullptr) return head;

    stack<Node*> st;
    Node* current = head;

    while (current != nullptr)
    {
        if (current->child != nullptr)
        {
            if (current->next != nullptr) st.push(current->next);

            current->next = current->child;
            current->next->prev = current;
            current->child = nullptr;
        }

        if (current->next == nullptr && !st.empty())
        {
            Node* resume = st.top();
            st.pop();
            current->next = resume;
            resume->prev = current;
        }

        current = current->next;
    }

    return head;
}

int main()
{
    Node* n1 = new Node(1); Node* n2 = new Node(2); Node* n3 = new Node(3);
    Node* n4 = new Node(4); Node* n5 = new Node(5); Node* n6 = new Node(6);
    Node* c7 = new Node(7); Node* c8 = new Node(8); Node* c9 = new Node(9); Node* c10 = new Node(10);

    n1->next=n2; n2->prev=n1; n2->next=n3; n3->prev=n2; n3->next=n4; n4->prev=n3;
    n4->next=n5; n5->prev=n4; n5->next=n6; n6->prev=n5;
    c7->next=c8; c8->prev=c7; c8->next=c9; c9->prev=c8; c9->next=c10; c10->prev=c9;
    n3->child = c7;

    Node* result = flatten(n1);
